local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxPlayGamesCtrl:LxBaseCtrl
local LxPlayGamesCtrl = classX("LxPlayGamesCtrl", LxBaseCtrl)

function LxPlayGamesCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
end

function LxPlayGamesCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end

-- 返回： 参数1：ture表示已开放; 参数2：未解锁条件
function LxPlayGamesCtrl:IsOpen(refId, showTips)
    local ref = ModuleCenter.PlayGames:GetPlayGamesRef(refId)
    if not ref then
        return false, ""
    end
    local funcId = ref.jumpId
    local tipsType = FuncOpenTipsEnum.None
    if showTips then
        tipsType = FuncOpenTipsEnum.Normal
    end

    if not CtrlCenter.FuncOpen:IsFuncOpen(funcId, tipsType) then
        return false, CtrlCenter.FuncOpen:GetNotOpenTips(funcId)
    end
    return true, ""
end

-- 获取玩法当前进度提示
function LxPlayGamesCtrl:GetCurProcessTips(refId, ref)
    if not ref then
        ref = ModuleCenter.PlayGames:GetPlayGamesRef(refId)
    end
    if ref.jumpId == FuncOpnIdConst.Pve then
        local twoerRefId = ModuleCenter.Tower:GetTowerCurBarrier()
        local twoerRef = ModuleCenter.Tower:OnTowerLevelRef(twoerRefId) or {}
        return I18nText(twoerRef.name)
    end

    return ""
end

return LxPlayGamesCtrl
